"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[133],{7290:(D,B,l)=>{l.r(B),l.d(B,{data:()=>e});const e=JSON.parse('{"key":"v-690f0782","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D1%81%D0%B0%D0%BC%D0%B0%D1%80%D1%81%D0%BA%D0%B8%D0%B9-%D0%BE%D0%B1%D0%B7%D0%BE%D1%80-%D0%BC%D0%BE%D0%BD%D0%BE%D0%B3%D1%80%D0%B0%D1%84%D0%B8%D0%B8-%D1%84%D0%B8%D0%BB%D0%BE%D1%81%D0%BE%D1%84%D1%81%D0%BA%D0%B8%D0%B5-%D0%B2%D0%B7%D0%B3%D0%BB%D1%8F%D0%B4%D1%8B-%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D0%B0.html","title":"Обзор монографии «Философские взгляды В. М. Глушкова»","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[],"git":{"updatedTime":1731178463000},"filePathRelative":"глушковские-чтения/самарский-обзор-монографии-философские-взгляды-глушкова.md"}')},4368:(D,B,l)=>{l.r(B),l.d(B,{default:()=>c});var e=l(6252);const t=(0,e._)("h1",{id:"обзор-монографии-«философские-взгляды-в-м-глушкова»",tabindex:"-1"},[(0,e._)("a",{class:"header-anchor",href:"#обзор-монографии-«философские-взгляды-в-м-глушкова»","aria-hidden":"true"},"#"),(0,e.Uk)(" Обзор монографии «Философские взгляды В. М. Глушкова»")],-1),a=(0,e._)("p",null,"Самарский А. Ю., г. Киев. Перевод с украинского.",-1),n=(0,e._)("p",null,"К 100-летию со дня рождения академика В. М. Глушкова преподавателями кафедры философии КПИ им. Игоря Сикорского была подготовлена монография «Философские взгляды В. М. Глушкова», исследующая его философские взгляды. Это — едва ли не первая попытка критически рассмотреть философские взгляды Глушкова через изучение его теоретических работ, биографических материалов и литературы о его идейном наследии.",-1),u=(0,e._)("p",null,"В его научном наследии насчитывается 19 статей на философские темы в престижных советских и европейских изданиях. Далеко не каждый из профессиональных философов того времени мог похвастаться подобным списком публикаций. Так же не каждый специалист по философии читал сложные для понимания книги Гегеля «Философия природы» и «Лекции по истории философии», которые Глушков прочитал, когда учился в девятом классе школы. А первая прочитанная им философская книга «Материализм и эмпириокритицизм» оставалась настольной книгой на протяжении всей жизни. Поэтому Виктор Михайлович, очевидно, не придерживался распространенного мнения, что философия, если и нужна ученому, то в основном «для общего развития». Его коллеги и ученики вспоминали, что он придавал философии большое значение, и считал, что она необходима для развития кибернетики и решения ее главных задач.",-1),r=(0,e._)("p",null,"Философские взгляды Глушкова эволюционировали на протяжении его жизни. Стоит заметить, что он считал нужным постоянно учиться и не стеснялся признавать, что чего-то не знает, и поэтому всегда был открыт для диалога. Поначалу вместе с большинством советских ученых он разделял позитивистские гносеологические представления. Наверное, это не столько недостаток ученых, ведь стихийно у них формируется именно позитивистское мышление, сколько это было общей проблемой советской философии. Ведь вместо того, чтобы указывать ученым на их очевидные философские ошибки и заблуждения, философы занимались «обобщением опыта науки», что было тем самым позитивизмом. Собственно, были философы с четкой диалектико-материалистической позицией (которой стремился придерживаться В.М. Глушков), однако они в силу разных причин ему не удалось наладить с ними плодотворное сотрудничество.",-1),p=(0,e._)("p",null,"Одним из таких философских заблуждений был взгляд на мышление как на функцию головного мозга, который был распространен в первые десятилетия развития кибернетики. В соответствии с этим, В. М. Глушков считал возможным смоделировать человеческое мышление и создать разумную машину. Кстати, хотя сама кибернетика впоследствии отказалась от этой идеи, и наука в целом отходит от такого представления, многие ученые продолжают отождествлять человеческий разум исключительно с деятельностью мозга.",-1),_=(0,e._)("p",null,"В контексте освещения философских взглядов Глушкова важной задачей оказалось показать роль гносеологии в кибернетике. Сам Виктор Михайлович придавал ей чрезвычайно важное значение, и обращался он именно к диалектической традиции в гносеологии. Возможно, этому способствовало его знакомство с книгами Г. В. Ф Гегеля в юности. Наверное, это, а также логика решения практических вопросов кибернетики, в частности в разрезе проекта ОГАС, помогло ему сформировать почти безупречные с точки зрения философии теоретические принципы кибернетики.",-1),d=(0,e._)("p",null,"Авторы книги рассматривают философские взгляды В. М. Глушкова на идейном фоне эпохи, ведь именно это позволяет оценить значимость идей пионера кибернетики. Стоит напомнить, что идейно та эпоха была очень насыщенной, и далеко не все идеи были прогрессивными. Несмотря на официальную однопартийность, идейная борьба была очень жесткой, и Виктор Михайлович оказался в центре этой борьбы. Ситуацию усугубляло то, что даже не все идейные друзья Глушкова умели отделить прогрессивные идеи от ретроградных. Например, ни один из философов-диалектиков не смогли увидеть первостепенную важность идеи ОГАС и способствовать ее философскому укреплению (что Глушкову-нефилософу пришлось делать самостоятельно).",-1),i=(0,e._)("p",null,"В книге Виктор Михайлович рассматривается как «практический материалист», и с точки зрения философии такая характеристика очень важна. Ведь еще со времен Маркса известно, что философам гораздо важнее способствовать «изменению мира», чем «его объяснению». Ставя целью реализацию ОГАС, Глушков действовал вполне диалектично: и как организатор, и как управленец. Его управленческие принципы с точки зрения философии особенно интересны. Они оказались такими практичными, поскольку были глубоко теоретическими и отточенными прежде всего с гносеологической точки зрения.",-1),h=(0,e._)("p",null,"Одной из важнейших философских способностей Глушкова было умение мыслить целостно. На этом в книге сосредоточено особое внимание. Именно на принципе целостности основывалась его идея ОГАС, и именно руководствуясь им возможна ее реализация. Чего, к сожалению, не могут понять и сегодня некоторые авторитетные историки и обозреватели информационных технологий, и что крайне важно для будущего.",-1),s={},c=(0,l(3744).Z)(s,[["render",function(D,B){const l=(0,e.up)("RouterLink");return(0,e.wg)(),(0,e.iD)("div",null,[t,a,(0,e._)("p",null,[(0,e.Uk)("Из материалов конференции "),(0,e.Wm)(l,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,e.w5)((()=>[(0,e.Uk)("«Глушковские чтения»")])),_:1}),(0,e.Uk)(" 2023 года.")]),n,u,r,p,_,d,i,h])}]])}}]);